ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name ?description WHERE {
  ?epoch a :Epoch .
  ?play a :Play .
  ?play p:hasEpoch ?epoch .
  ?epoch p:name ?name .
  ?epoch p:description ?description .
  ?play p:title ?title_f .
  FILTER(STR(?title_f) = "Hamlet")
} }
  full: { SELECT ?name ?description ?name2 ?culture WHERE {
  ?epoch a :Epoch .
  ?play a :Play .
  ?play p:hasEpoch ?epoch .
  ?society a :Society .
  ?play p:hasSociety ?society .
  ?epoch p:name ?name .
  ?epoch p:description ?description .
  ?society p:name ?name2 .
  ?society p:culture ?culture .
  ?play p:title ?title_f .
  FILTER(STR(?title_f) = "Hamlet")
} }
  component_2: { SELECT ?name ?culture WHERE {
  ?society a :Society .
  ?play a :Play .
  ?play p:hasSociety ?society .
  ?society p:name ?name .
  ?society p:culture ?culture .
  ?play p:title ?title_f .
  FILTER(STR(?title_f) = "Hamlet")
} }
}
